return [{
  json: {
    spreadsheetId: "1Txyuj08oqwGtsyBZ9Llorb0oygPBWDz3RisGomy1Evg",
    masterSheetName: "Master",
    calendarSheetName: "Calendar",
    safeMode: true,
    logDrainUrl: "https://n8n.pureremedysolutions.com/webhook/log-drain",
    smtpFrom: "Influencer Factory <kspandian32@gmail.com>",
    sheetUrl: "https://docs.google.com/spreadsheets/d/1Txyuj08oqwGtsyBZ9Llorb0oygPBWDz3RisGomy1Evg/edit"
  }
}];

const charAi = JSON.parse($node["🤖 AI: Character Sheet"].json.message.content.replace(/```json/gi, '').replace(/```/g, '').trim());
const form = $node["📋 Influencer Brief"].json;

return [{
  json: {
    Name: form["Influencer Name"],
    Handle: form["Instagram Handle"],
    Niche: form["Niche"],
    Gender: "Generated",
    Age: "24",
    Location: "India",
    Personality: charAi.personality,
    Aesthetic: charAi.aesthetic,
    Bio: charAi.bio,
    "Hashtag Bank": charAi.hashtags,
    Timestamp: new Date().toISOString()
  }
}];

const content = $node["🤖 AI: 30-Day Calendar"].json.message.content.replace(/```json/gi, '').replace(/```/g, '').trim();
const calAi = JSON.parse(content + (content.endsWith("]") ? "" : "]"));
const form = $node["📋 Influencer Brief"].json;
const influencer = form["Influencer Name"] + " (" + form["Instagram Handle"] + ")";

if (!Array.isArray(calAi)) return [];

return calAi.map(day => ({ json: {
  Influencer: influencer,
  Day: day.day,
  Type: day.type,
  "Photo Description": day.photo_description,
  "Ideogram Prompt": day.ideogram_prompt,
  Caption: day.caption,
  Hashtags: day.hashtags,
  "Posting Time": day.posting_time,
  "Image Status": "Not Generated",
  "Video Status": "Not Generated",
  Posted: "No"
} }));
